import React from 'react';
import { NavLink, useLocation } from 'react-router-dom';

const Sidebar = ({ userRole }) => {
  const location = useLocation();

  const getMenuItems = () => {
    const commonItems = [
      { path: '/dashboard', name: 'Dashboard', icon: '📊' },
    ];

    const roleBasedItems = {
      admin: [
        { path: '/users', name: 'Users', icon: '👥' },
        { path: '/reports', name: 'Reports', icon: '📈' },
        { path: '/settings', name: 'Settings', icon: '⚙️' },
      ],
      doctor: [
        { path: '/appointments', name: 'Appointments', icon: '📅' },
        { path: '/patients', name: 'Patients', icon: '👨‍⚕️' },
        { path: '/consultation', name: 'Consultation', icon: '🩺' },
        { path: '/prescriptions', name: 'Prescriptions', icon: '💊' },
        { path: '/lab-orders', name: 'Lab Orders', icon: '🔬' },
      ],
      receptionist: [
        { path: '/appointments', name: 'Appointments', icon: '📅' },
        { path: '/patients', name: 'Patients', icon: '👥' },
        { path: '/queue', name: 'Queue', icon: '🚶‍♂️' },
        { path: '/payments', name: 'Payments', icon: '💰' },
      ],
      nurse: [
        { path: '/triage', name: 'Triage', icon: '🏥' },
        { path: '/vitals', name: 'Vitals', icon: '❤️' },
        { path: '/patients', name: 'Patients', icon: '👥' },
        { path: '/consultation', name: 'Consultation', icon: '🩺' },
      ],
      lab_technician: [
        { path: '/lab-tests', name: 'Lab Tests', icon: '🔬' },
        { path: '/results', name: 'Results', icon: '📋' },
      ],
      pharmacist: [
        { path: '/prescriptions', name: 'Prescriptions', icon: '💊' },
        { path: '/inventory', name: 'Inventory', icon: '📦' },
        { path: '/dispensing', name: 'Dispensing', icon: '💉' },
      ],
    };

    return [...commonItems, ...(roleBasedItems[userRole] || [])];
  };

  const menuItems = getMenuItems();

  return (
    <div className="w-64 bg-gray-900 text-white min-h-screen">
      <div className="p-6">
        <h1 className="text-2xl font-bold text-blue-400">Patient Management</h1>
        <p className="text-sm text-gray-400 mt-2">Agmas Medium Clinic</p>
      </div>

      <nav className="mt-8">
        {menuItems.map((item) => {
          const isActive = location.pathname === item.path;
          return (
            <NavLink
              key={item.path}
              to={item.path}
              className={`flex items-center px-6 py-3 text-sm font-medium transition-colors duration-200 ${isActive
                ? 'bg-blue-600 text-white border-r-4 border-blue-400'
                : 'text-gray-300 hover:bg-gray-800 hover:text-white'
                }`}
            >
              <span className="mr-3 text-lg">{item.icon}</span>
              {item.name}
            </NavLink>
          );
        })}
      </nav>
    </div>
  );
};

export default Sidebar;
